// ╔══════════════════════════════════════════════════════════╗
// ║  CONFIGURATION — Edit these values to customise         ║
// ╚══════════════════════════════════════════════════════════╝
const CONFIG = {
  // Email recipient for the organisation report
  EMAIL_RECIPIENT: 'fabian@fdnxt.com',

  // Google Sheet ID for the central TAS_N8N_Audit sheet
  SHEET_ID: $env.TAS_AUDIT_SHEET_ID || 'YOUR_GOOGLE_SHEET_ID_HERE',

  // Tab name within the audit sheet
  SHEET_TAB: 'Workflow_Organisation',

  // Set to true to actually apply tags via API
  // Set to false for report-only mode
  AUTO_APPLY_TAGS: true,

  // ── TAG RULES ──────────────────────────────────────────
  // Each rule: { pattern: 'regex string', tag: 'tag-name', priority: number }
  // Higher priority = applied first. All matching tags are applied.
  TAG_RULES: [
    // Platform tags
    { pattern: 'drive|gdrive|google.?drive', tag: 'google-drive', priority: 10 },
    { pattern: 'sheet|spreadsheet', tag: 'google-sheets', priority: 10 },
    { pattern: 'email|gmail|mail', tag: 'email', priority: 10 },
    { pattern: 'slack', tag: 'slack', priority: 10 },
    { pattern: 'zoho', tag: 'zoho', priority: 10 },
    { pattern: 'webhook', tag: 'webhook', priority: 8 },
    { pattern: 'notion', tag: 'notion', priority: 10 },
    { pattern: 'airtable', tag: 'airtable', priority: 10 },
    { pattern: 'stripe|payment', tag: 'stripe', priority: 10 },
    { pattern: 'whatsapp|wa\\b', tag: 'whatsapp', priority: 10 },
    { pattern: 'xero|quickbooks', tag: 'accounting', priority: 10 },

    // Function tags
    { pattern: 'cron|schedule|daily|weekly|hourly', tag: 'scheduled', priority: 5 },
    { pattern: 'backup|sync|mirror', tag: 'backup', priority: 7 },
    { pattern: 'test|debug|dev|experiment', tag: 'testing', priority: 3 },
    { pattern: 'client|customer|crm|lead', tag: 'clients', priority: 6 },
    { pattern: 'invoice|billing|payment|quote', tag: 'finance', priority: 6 },
    { pattern: 'report|analytics|dashboard|metric', tag: 'reporting', priority: 6 },
    { pattern: 'n8n|cleanup|maintain|audit', tag: 'maintenance', priority: 4 },
    { pattern: 'onboard|intake|welcome', tag: 'onboarding', priority: 7 },
    { pattern: 'notify|alert|reminder', tag: 'notifications', priority: 5 },

    // Business tags
    { pattern: 'tas|fdnxt', tag: 'TAS', priority: 9 },
    { pattern: 'sop|process|procedure', tag: 'SOP', priority: 7 }
  ],

  // ── FOLDER RULES ───────────────────────────────────────
  // Each rule: { pattern: 'regex string', folder: 'Folder Name', priority: number }
  // Highest priority match wins (only ONE folder per workflow).
  FOLDER_RULES: [
    { pattern: 'drive|gdrive|sheet|spreadsheet|google', folder: 'Google Workspace', priority: 10 },
    { pattern: 'email|gmail|slack|whatsapp|communication|notify', folder: 'Communications', priority: 9 },
    { pattern: 'zoho|crm|client|customer|lead', folder: 'CRM & Clients', priority: 8 },
    { pattern: 'invoice|billing|payment|finance|quote|xero|stripe', folder: 'Finance', priority: 8 },
    { pattern: 'backup|sync|mirror', folder: 'Sync & Backup', priority: 7 },
    { pattern: 'test|debug|dev|experiment', folder: 'Development', priority: 3 },
    { pattern: 'report|analytics|dashboard|metric', folder: 'Reporting', priority: 6 },
    { pattern: 'n8n|cleanup|maintain|cron|schedule|audit', folder: 'System & Maintenance', priority: 5 },
    { pattern: 'onboard|intake|welcome|sop', folder: 'Onboarding & SOPs', priority: 7 },
    { pattern: 'tas|fdnxt', folder: 'TAS Core', priority: 4 }
  ]
};

return [{ json: CONFIG }];

const config = $('⚙️ Configuration').first().json;
const workflows = $input.first().json.data || [];

// Compile regex patterns with priority sorting
const tagRules = config.TAG_RULES
  .map(r => ({ ...r, regex: new RegExp(r.pattern, 'i') }))
  .sort((a, b) => b.priority - a.priority);

const folderRules = config.FOLDER_RULES
  .map(r => ({ ...r, regex: new RegExp(r.pattern, 'i') }))
  .sort((a, b) => b.priority - a.priority);

const results = [];

for (const wf of workflows) {
  const matchedTags = [];
  const tagConfidences = [];
  let matchedFolder = 'Uncategorised';
  let folderConfidence = 0;
  let folderMatchedRule = 'none';

  // ── Tag matching with confidence ──
  for (const rule of tagRules) {
    const nameMatch = rule.regex.test(wf.name);
    // Also check node types for deeper confidence
    const nodeTypes = (wf.nodes || []).map(n => n.type || '').join(' ');
    const nodeMatch = rule.regex.test(nodeTypes);

    if (nameMatch || nodeMatch) {
      const confidence = nameMatch && nodeMatch ? 1.0
        : nameMatch ? 0.8
        : 0.5;

      matchedTags.push(rule.tag);
      tagConfidences.push({
        tag: rule.tag,
        confidence: Math.round(confidence * 100),
        source: nameMatch && nodeMatch ? 'name+nodes'
          : nameMatch ? 'name'
          : 'nodes',
        priority: rule.priority
      });
    }
  }

  // ── Folder matching (highest priority wins) ──
  for (const rule of folderRules) {
    if (rule.regex.test(wf.name)) {
      matchedFolder = rule.folder;
      folderConfidence = rule.priority * 10;
      folderMatchedRule = rule.pattern;
      break;
    }
  }

  // Check existing tags
  const existingTags = (wf.tags || []).map(t => t.name);
  const newTags = matchedTags.filter(t => !existingTags.includes(t));
  const allTags = [...new Set([...existingTags, ...matchedTags])];

  results.push({
    workflowId: wf.id,
    workflowName: wf.name,
    active: wf.active,
    nodeCount: (wf.nodes || []).length,
    existingTags: existingTags.join(', '),
    newTags: newTags.join(', '),
    allTags: allTags.join(', '),
    newTagCount: newTags.length,
    folder: matchedFolder,
    folderConfidence,
    folderMatchedRule,
    tagConfidences,
    needsUpdate: newTags.length > 0,
    timestamp: new Date().toISOString()
  });
}

// Sort: items needing updates first
results.sort((a, b) => b.newTagCount - a.newTagCount);

return results.map(r => ({ json: r }));

const config = $('⚙️ Configuration').first().json;

if (!config.AUTO_APPLY_TAGS) {
  return $input.all().map(i => ({ json: { ...i.json, tagUpdateStatus: 'SKIPPED_DRY_RUN' } }));
}

const BASE_URL = $env.N8N_BASE_URL;
const API_KEY = $env.N8N_API_KEY;

// Step 1: Get all existing tags
let tagsResp;
try {
  tagsResp = await this.helpers.httpRequest({
    method: 'GET',
    url: `${BASE_URL}/api/v1/tags`,
    headers: { 'X-N8N-API-KEY': API_KEY }
  });
} catch (err) {
  return $input.all().map(i => ({ json: { ...i.json, tagUpdateStatus: 'FAILED_FETCH_TAGS', error: err.message } }));
}

const existingTags = tagsResp.data || tagsResp || [];
const tagMap = {};
for (const t of existingTags) {
  tagMap[t.name] = t.id;
}

const results = [];

for (const item of $input.all()) {
  const wf = item.json;
  const allTagNames = wf.allTags.split(', ').filter(Boolean);

  // Create missing tags
  for (const tagName of allTagNames) {
    if (!tagMap[tagName]) {
      try {
        const created = await this.helpers.httpRequest({
          method: 'POST',
          url: `${BASE_URL}/api/v1/tags`,
          headers: { 'X-N8N-API-KEY': API_KEY, 'Content-Type': 'application/json' },
          body: { name: tagName }
        });
        tagMap[tagName] = created.id;
      } catch (err) {
        // Tag may already exist from concurrent creation
      }
    }
  }

  // Apply tags to workflow
  const tagIds = allTagNames.map(t => tagMap[t]).filter(Boolean);
  try {
    await this.helpers.httpRequest({
      method: 'PATCH',
      url: `${BASE_URL}/api/v1/workflows/${wf.workflowId}`,
      headers: { 'X-N8N-API-KEY': API_KEY, 'Content-Type': 'application/json' },
      body: { tags: tagIds.map(id => ({ id })) }
    });
    results.push({ json: { ...wf, tagUpdateStatus: 'OK' } });
  } catch (err) {
    results.push({ json: { ...wf, tagUpdateStatus: 'FAILED', error: err.message } });
  }
}

return results;

const allItems = $('Classify by Tags & Folders').all();
const config = $('⚙️ Configuration').first().json;

// Group by folder
const folders = {};
for (const item of allItems) {
  const wf = item.json;
  const folder = wf.folder || 'Uncategorised';
  if (!folders[folder]) folders[folder] = [];
  folders[folder].push(wf);
}

const folderSummary = Object.entries(folders)
  .map(([name, workflows]) => ({
    folder: name,
    count: workflows.length,
    activeCount: workflows.filter(w => w.active).length,
    workflows
  }))
  .sort((a, b) => b.count - a.count);

// Build stats
const totalTagged = allItems.filter(i => i.json.needsUpdate).length;
const totalUntagged = allItems.filter(i => !i.json.allTags).length;

// Build HTML
const folderHtml = folderSummary.map(f => {
  const rows = f.workflows.map(w => {
    const status = w.active ? '✅' : '⏸️';
    const confidences = (w.tagConfidences || []).map(tc =>
      `${tc.tag}(${tc.confidence}%)`
    ).join(', ');
    return `<tr><td>${status}</td><td>${w.workflowName}</td><td>${w.allTags || 'none'}</td><td>${confidences || '-'}</td><td>${w.needsUpdate ? '🆕 YES' : 'no'}</td></tr>`;
  }).join('');

  return `<h3>📁 ${f.folder} (${f.count} workflows, ${f.activeCount} active)</h3>
    <table border="1" cellpadding="5" style="border-collapse:collapse;width:100%">
    <tr><th>St</th><th>Name</th><th>Tags</th><th>Confidence</th><th>Updated?</th></tr>
    ${rows}</table>`;
}).join('<hr>');

const html = `
<h2>📂 TAS Workflow Organisation Report</h2>
<p><strong>Run:</strong> ${new Date().toISOString()}</p>
<p><strong>Mode:</strong> ${config.AUTO_APPLY_TAGS ? '🟢 LIVE (tags applied)' : '🔵 DRY RUN (report only)'}</p>
<hr>
<table style="border-collapse:collapse;width:100%">
<tr><th>Metric</th><th>Count</th></tr>
<tr><td>Total workflows</td><td><strong>${allItems.length}</strong></td></tr>
<tr><td>📁 Folders identified</td><td><strong>${folderSummary.length}</strong></td></tr>
<tr><td>🏷️ Newly tagged this run</td><td><strong>${totalTagged}</strong></td></tr>
<tr><td>❓ No tags matched</td><td><strong>${totalUntagged}</strong></td></tr>
</table>
<hr>
${folderHtml}
<hr>
<p><em>Full audit trail logged to Google Sheet: TAS_N8N_Audit → Workflow_Organisation</em></p>
<p><em>To create actual N8N folders, use these groupings as a guide.</em></p>
`;

return [{
  json: {
    html,
    recipient: config.EMAIL_RECIPIENT,
    subject: `TAS N8N Audit: ${allItems.length} workflows organised into ${folderSummary.length} folders, ${totalTagged} newly tagged`
  }
}];
